Code.Terraform:
```hcl
resource "aws_cloudtrail" "<example_resource_name>" {
  name           = "<example_resource_name>"
  s3_bucket_name = "<example_resource_name>"

  event_selector {
    data_resource {
      type   = "AWS::Lambda::Function"  # 关键：启用 Lambda 数据事件
      values = ["arn:aws:lambda:<REGION>:<ACCOUNT_ID>:function"]  # 关键：捕获此账户/区域中所有函数的 Invoke
    }
  }
}
```
